valueString.value:
/* End of Services for responding to violence against women C.DE169 */

/*
@dataElement: HIV.D.DE1 - Reason for visit
@activity: HIV.D1 Determine reason for visit
@description: Whether visit was scheduled or unscheduled, clinical only, or for ARV drug pick-up
*/
define "Reason for visit D.DE1":
  [Observation: Concepts."Reason for visit - HIV.D.DE1"] O
    where O.status in { 'final', 'amended', 'corrected' }

/* End of Services for responding to violence against women C.DE169 */

/*
@dataElement: HIV.D.DE1 - Reason for visit
@activity: HIV.D1 Determine reason for visit
@description: Whether visit was scheduled or unscheduled, clinical only, or for ARV drug pick-up
*/
define "Reason for visit D.DE1":
  Elements."Reason for visit D.DE1" O
    where O.encounter.references(EncounterId)

/*
 @input: "Reason for Visit"
 @pseudocode: "Reason for visit"='HIV testing services visit'
 */
define "HIV testing services visit":
  exists(
    Elements."Reason for visit D.DE1" O
      where O.value ~ Concepts."HIV testing services visit"
  )

/**
 * HIV Elements
 */

// Auto-generated Elements from DAK Data Dictionary
//   Entries based on DAK Data Dictionary for Data Elements marked as used
//   in at least one Decision Support Table or Aggregate Indicator

/*
@dataElement: HIV.A.DE17 - Age
@activity: HIV.A6.1 Review sociodemographic data with client | HIV.A5 Create new client record
@description: Calculated age (number of years) of the client based on date of birth
*/
/** 
 * @dataElement Patient age in years
 */
define "Current Patient Age In Years":
  AgeInYearsAt(Today())

/*
 @input: "Age"
 @pseudocode: "Age" ≥ 20 years
 */
define "Age 20 or older":
  Elements."Current Patient Age In Years" >= 20

/* End of Date informed of HIV-positive diagnosis */

/*
@activity: HIV.B7 Test for HIV using testing algorithm
*/
define "HIV test":
  [Observation: Concepts."HIV test type - HIV.B.DE81 Choices"] O
  where O.status in { 'final', 'amended', 'corrected' }

/* End of HIV test date B.DE110 */

/*
@dataElement: HIV.B.DE111 - HIV test result
@activity: HIV.B7 Test for HIV using testing algorithm
@description: The result from HIV testing after applying the testing algorithm
*/
// Same as test - see profile
define "HIV test result Observation":
  "HIV test" O

/* End of Invalid B.DE109 */

/*
@dataElement: HIV.B.DE111 - HIV test result
@activity: HIV.B7 Test for HIV using testing algorithm
@description: The result from HIV testing after applying the testing algorithm
*/
define "HIV test result":
  Elements."HIV test result Observation" O
    where O.encounter.references(EncounterId)

/*
 @input: "HIV test result"
 @pseudocode: "HIV test result"='HIV-positive'
 */
define "HIV Positive test result":
  exists(
    Elements."HIV test result" O
      where O.value ~ Concepts."HIV-positive"
  )

/* End of Serodiscordant partner D.DE37 */

/*
@dataElement: HIV.D.DE38 - On ART
@activity: HIV.D8 Capture or update client history
@description: Client is currently taking ART
*/

define "On ART D.DE38":
    [MedicationStatement] MS
    where exists(MS.reasonCode C where C ~ Concepts."On ART - HIV.D.DE38")
    sort by start of effective.toInterval()

/* End of Serodiscordant partner D.DE37 */

/*
@dataElement: HIV.D.DE38 - On ART
@activity: HIV.D8 Capture or update client history
@description: Client is currently taking ART
*/
define "On ART D.DE38":
  Elements."On ART D.DE38" MS
    where MS.context.references(EncounterId)

/*
 @input: "On ART"
 @pseudocode: "On ART"=False
 */
define "Not on ART":
  not(exists(
    Elements."On ART D.DE38"
  ))

/*
 @input: "Age"
 @pseudocode: ""Age"<20 years
 */
define "Age under 20":
  Elements."Current Patient Age In Years" < 20

/* End of Neutropenia */

/*
@dataElement: HIV.D.DE364 - CD4 count
@activity: HIV.D20 Diagnostics
@description: CD4 cell count in cells/mm^3
*/
// TODO: Replace placeholder with relevant CQL logic
define "CD4 count D.DE364":
  [Observation: Concepts."CD4 count - HIV.D.DE364"] O
    where O.status in { 'final', 'amended', 'corrected' }

/* End of WHO HIV clinical stage condition or symptom D.DE289 */

/*
@dataElement: HIV.D.DE364 - CD4 count
@activity: HIV.D20 Diagnostics
@description: CD4 cell count in cells/mm^3
*/
define "CD4 count D.DE364":
  Elements."CD4 count D.DE364" O
    where O.encounter.references(EncounterId)

/*
 @input: "CD4 count"
 @pseudocode: "CD4 count" ≤ 100 cells/mm3
 */
define "CD4 less than or equal to 100 cells/mm3":
  exists(
    Elements."CD4 count D.DE364" O
      where O.value <= 100
  )

/* End of Age */

/*
@dataElement: HIV.A.DE18 - Gender
@activity: HIV.A6.1 Review sociodemographic data with client | HIV.A5 Create new client record
@description: Gender of the client
*/
// TODO: Replace placeholder with relevant CQL logic
define "Gender":
  Patient.gender

/* End of Gender */

/*
@dataElement: HIV.A.DE19 - Female
@activity: HIV.A6.1 Review sociodemographic data with client | HIV.A5 Create new client record
@description: Client identifies as female
*/
define "Female":
  "Gender" ~ 'female'

/*
 @input: "Gender"
 @pseudocode: "Gender"='Female'
 */
define "Client is female":
  Elements."Female"

/*
 @input: "Reason for Visit"
 @pseudocode: "Reason for visit"='ART initiation'
 */
define "ART initiation visit":
  exists(
    Elements."Reason for visit D.DE1" O
      where O.value ~ Concepts."ART initiation"
  )

/*
  @input: "Age"
  @pseudocode: 'Age' ≥ 10 years
  */
define "Age 10 or older":
  Elements."Current Patient Age In Years" >= 10

/*
 @input: "CD4 count"
 @pseudocode: "CD4 count" ≤ 200 cells/mm3
 */
define "CD4 less than or equal to 200 cells/mm3":
  exists(
    Elements."CD4 count D.DE364" O
      where O.value <= 200
  )

/*
 @input: "Current medications"
 @pseudocode: "Current medications"='AZT'
 */
define "On AZT":
  exists(
    Elements."On ART D.DE38" MS
      where MS.medication ~ Concepts."AZT"
  )

/*
 @input: "Current medications"
 @pseudocode: "Current medications"='TDF'
 */
define "On TDF":
  exists(
    Elements."On ART D.DE38" MS
      where MS.medication ~ Concepts."TDF - HIV.D.DE135"
  )

/*
 @input: "Reason for Visit"
 @pseudocode: "Reason for visit"='Clinical visit
 */
define "Clinical visit":
  exists(
    Elements."Reason for visit D.DE1" O
      where O.value ~ Concepts."Clinical visit - HIV.D.DE3"
  )

/*
 @input: "On ART"
 @pseudocode: "On ART"=True
 */
define "On ART":
  exists(
    Elements."On ART D.DE38"
  )

/* End of Dose adjustment recommended */

/*
@dataElement: HIV.D.DE443 - Suspicion of treatment failure or interruption
@activity: HIV.D23 Prescribe
@description: Client has been on ART, but has stopped taking it or a treatment failure is suspected
*/
define "Suspicion of treatment failure or interruption Observation":
  Elements."Suspicion of treatment failure or interruption Observation" O
    where O.encounter.references(EncounterId)

/*
 @input: "Suspicion of treatment failure or interruption"
 @pseudocode: "Suspicion of treatment failure or interruption"=True
 */
define "Suspicion of treatment failure or interruption":
  exists(
    Elements."Suspicion of treatment failure or interruption Observation" O
      where O.value = true
  )

/*
@description: Returns true if the given reference is to the given resourceId
@comment: Returns true if the `resourceId` parameter exactly equals the tail of the given reference.
NOTE: This function assumes resources from the same source server.
*/
define fluent function references(reference FHIR.Reference, resourceId String):
  resourceId = Last(Split(reference.reference, '/'))
